// src/UploadImage.js
import React, { useState } from "react";
import ReactMarkdown from "react-markdown";
import remarkGfm from "remark-gfm";
import { analyzeImage } from "./api";
import { ClipLoader } from "react-spinners";

function UploadImage() {
  const [file, setFile] = useState(null);
  const [report, setReport] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [age, setAge] = useState("");
  const [sex, setSex] = useState("");

  const handleFileChange = (e) => {
    const selectedFile = e.target.files[0];
    if (!selectedFile) return;

    if (!selectedFile.type.startsWith("image/")) {
      setError("Please upload a medical image (JPEG/PNG/DICOM)");
      return;
    }

    setFile(selectedFile);
    setError("");
    setReport("");
  };

  const handleUpload = async () => {
    if (!file) {
      setError("Please select an imaging file");
      return;
    }

    if (!age || !sex) {
      setError("Patient demographics required for analysis");
      return;
    }

    setLoading(true);
    setError("");
    setReport("");

    try {
      const formData = new FormData();
      formData.append("file", file);
      formData.append("age", age);
      formData.append("sex", sex);

      const data = await analyzeImage(formData);

      if (data?.analysis) {
        setReport(data.analysis);
      } else {
        setError(data?.detail || "Failed to generate imaging analysis");
      }
    } catch (err) {
      console.error("DICOM processing error:", err);
      setError(err.message || "Medical image analysis failed");
    } finally {
      setLoading(false);
    }
  };

  const extractTextContent = (children) => {
    return React.Children.toArray(children)
      .map(child => {
        if (typeof child === 'string') return child;
        if (child?.props?.children) return extractTextContent(child.props.children);
        return '';
      })
      .join('')
      .replace(/\s+/g, ' ')
      .trim();
  };

  const MarkdownComponents = {
    strong({ node, children }) {
      const textContent = extractTextContent(children);

      // Medical imaging specific pattern matching
      const certaintyMatch = textContent.match(
        /(.*?)\s*\(([Cc]ertainty:\s*\d{1,3}%)\)/
      );

      if (certaintyMatch) {
        return (
          <span className="font-semibold text-brandDark dark:text-gray-100">
            {certaintyMatch[1]}
            <span className="text-brandBlue-600 dark:text-brandBlue-400 ml-1.5">
              ({certaintyMatch[2]})
            </span>
          </span>
        );
      }

      // Highlight critical findings
      const criticalMatch = textContent.match(/CRITICAL:/i);
      if (criticalMatch) {
        return (
          <span className="font-bold text-diagnosticRed dark:text-red-400">
            {children}
          </span>
        );
      }

      return <strong className="text-brandDark dark:text-gray-200">{children}</strong>;
    },
    ul: ({ node, children }) => (
      <ul className="list-disc pl-6 mb-4 space-y-2 marker:text-brandBlue-500 dark:marker:text-brandBlue-300">
        {children}
      </ul>
    ),
    li: ({ node, children }) => (
      <li className="mb-2 text-gray-700 dark:text-gray-300">
        {children}
      </li>
    ),
    p: ({ node, children }) => (
      <p className="mb-4 leading-relaxed text-gray-800 dark:text-gray-200">
        {children}
      </p>
    ),
    h3: ({ node, children }) => (
      <h3 className="text-xl font-semibold mt-8 mb-4 text-brandBlue-800 dark:text-brandBlue-200 border-b pb-2 border-brandBlue-200 dark:border-brandBlue-700">
        {children}
      </h3>
    )
  };

  return (
    <div className="p-6 bg-white dark:bg-brandDark rounded-xl shadow-medical max-w-4xl mx-auto">
      <h2 className="text-3xl font-bold mb-8 text-center text-brandBlue-800 dark:text-brandBlue-200 font-heading">
        Medical Imaging Analysis Suite
      </h2>

      <div className="space-y-6">
        {/* File Upload Section */}
        <div className="space-y-3">
          <label className="block text-lg font-medium text-brandBlue-700 dark:text-brandBlue-300">
            Upload Diagnostic Image
          </label>
          <div className="relative">
            <input
              type="file"
              onChange={handleFileChange}
              accept="image/*,.dcm"
              className="block w-full text-lg text-gray-600
                file:mr-6 file:py-3 file:px-6
                file:rounded-xl file:border-0
                file:text-lg file:font-semibold
                file:bg-brandBlue-600 file:text-white
                hover:file:bg-brandBlue-700 transition-colors
                cursor-pointer disabled:cursor-not-allowed
                dark:file:bg-brandBlue-700 dark:hover:file:bg-brandBlue-800"
            />
            <span className="absolute right-4 top-3 text-gray-400 dark:text-gray-500">
              ⚡ DICOM supported
            </span>
          </div>
        </div>

        {/* Patient Demographics */}
        <div className="grid grid-cols-2 gap-6">
          <div className="space-y-2">
            <label className="block text-sm font-medium text-brandBlue-700 dark:text-brandBlue-300">
              Patient Age
            </label>
            <input
              type="number"
              value={age}
              onChange={(e) => setAge(e.target.value.replace(/[^0-9]/g, ''))}
              min="0"
              max="120"
              className="w-full p-3 border-2 rounded-lg
                bg-white dark:bg-gray-800
                border-brandBlue-200 dark:border-brandBlue-700
                focus:ring-2 focus:ring-brandBlue-500
                text-brandDark dark:text-gray-200"
              placeholder="Age"
              required
            />
          </div>
          <div className="space-y-2">
            <label className="block text-sm font-medium text-brandBlue-700 dark:text-brandBlue-300">
              Biological Sex
            </label>
            <select
              value={sex}
              onChange={(e) => setSex(e.target.value)}
              className="w-full p-3 border-2 rounded-lg
                bg-white dark:bg-gray-800
                border-brandBlue-200 dark:border-brandBlue-700
                focus:ring-2 focus:ring-brandBlue-500
                text-brandDark dark:text-gray-200"
              required
            >
              <option value="">Select Sex</option>
              <option value="Male">Male</option>
              <option value="Female">Female</option>
              <option value="Other">Other</option>
            </select>
          </div>
        </div>

        {/* Analysis Trigger */}
        <button
          onClick={handleUpload}
          disabled={loading || !file}
          className={`w-full py-4 px-8 rounded-xl font-bold text-lg
            transition-all duration-200 ${
              loading || !file
                ? 'bg-gray-300 cursor-not-allowed dark:bg-gray-700'
                : 'bg-brandBlue-600 hover:bg-brandBlue-700 dark:bg-brandBlue-700 dark:hover:bg-brandBlue-800'
            } text-white`}
        >
          {loading ? (
            <div className="flex items-center justify-center gap-3">
              <ClipLoader color="#ffffff" size={26} />
              <span>Analyzing Medical Image...</span>
            </div>
          ) : (
            'Start Diagnostic Analysis'
          )}
        </button>

        {/* Error Reporting */}
        {error && (
          <div className="p-4 bg-red-100/90 dark:bg-red-900/50
            text-red-700 dark:text-red-200 rounded-lg
            border-2 border-red-200 dark:border-red-800
            flex items-center gap-3">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 flex-shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
            </svg>
            <span>{error}</span>
          </div>
        )}

        {/* AI Analysis Report */}
        {report && !error && (
          <div className="mt-8 bg-white/90 dark:bg-gray-800/95
            p-8 rounded-xl shadow-medical
            border-2 border-brandBlue-100 dark:border-brandBlue-800">
            <h3 className="text-2xl font-bold mb-6 text-brandBlue-800 dark:text-brandBlue-200">
              AI Diagnostic Report
            </h3>
            <div className="medical-prose dark:medical-prose-invert">
              <ReactMarkdown
                remarkPlugins={[remarkGfm]}
                components={MarkdownComponents}
              >
                {report}
              </ReactMarkdown>
            </div>
            <div className="mt-8 p-4 bg-yellow-100/80 dark:bg-yellow-900/50
              rounded-lg border-2 border-yellow-200 dark:border-yellow-800
              flex items-start gap-3">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 flex-shrink-0 text-yellow-600 dark:text-yellow-300" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M8.257 3.099c.765-1.36 2.722-1.36 3.486 0l5.58 9.92c.75 1.334-.213 2.98-1.742 2.98H4.42c-1.53 0-2.493-1.646-1.743-2.98l5.58-9.92zM11 13a1 1 0 11-2 0 1 1 0 012 0zm-1-8a1 1 0 00-1 1v3a1 1 0 002 0V6a1 1 0 00-1-1z" clipRule="evenodd" />
              </svg>
              <p className="text-sm text-yellow-800 dark:text-yellow-200 leading-relaxed">
                This AI-powered preliminary analysis must be validated by a board-certified radiologist. 
                Clinical context and additional diagnostic procedures may be required for accurate diagnosis.
              </p>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

